def divi(n):
    if n == 0:
        return 0
    elif n == 1:
        return 1
    elif n == 11:
        return 2
    elif n % 11 <= 6:
        return n % 11
    else:
        return 11 - (n % 11) + 2

def divide_maior(n):
    if n == 0:
        return 0
    divisao = n // 11
    resto = n % 11
    valor_menor_que_onze = divi(resto)
    valor_maior_que_onze = divisao * 2
    return valor_maior_que_onze + valor_menor_que_onze

